// services/uploadService.js
const API_URL = 'http://localhost:5000/api';

/**
 * Upload a file with authentication
 */
export const uploadFile = async (formData) => {
  try {
    console.log('📤 Starting file upload...');
    
    // Get JWT token from localStorage
    const token = localStorage.getItem('token');
    
    // Check if token exists
    if (!token) {
      console.error('❌ No authentication token found');
      throw new Error('You need to login first. Please login and try again.');
    }
    
    console.log('🔑 Token found, length:', token.length);
    
    // Create headers
    const headers = {};
    headers['Authorization'] = `Bearer ${token}`;
    // NOTE: Do NOT set Content-Type for FormData
    
    // Make the request
    const response = await fetch(`${API_URL}/upload`, {
      method: 'POST',
      headers: headers,
      body: formData,
    });
    
    console.log('📡 Upload response status:', response.status);
    
    // Handle different response statuses
    if (!response.ok) {
      let errorMessage = `Upload failed with status: ${response.status}`;
      
      try {
        const errorData = await response.json();
        errorMessage = errorData.error || errorData.message || errorMessage;
      } catch (e) {
        // If response is not JSON
        const errorText = await response.text();
        errorMessage = errorText || errorMessage;
      }
      
      // Special handling for auth errors
      if (response.status === 401) {
        // Clear invalid token
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        errorMessage = 'Session expired. Please login again.';
      }
      
      if (response.status === 403) {
        errorMessage = 'You do not have permission to upload files.';
      }
      
      throw new Error(errorMessage);
    }
    
    // Parse successful response
    const data = await response.json();
    console.log('✅ Upload successful:', data);
    return data;
    
  } catch (error) {
    console.error('❌ Upload error details:', {
      message: error.message,
      name: error.name,
      stack: error.stack
    });
    
    // Re-throw with user-friendly message
    if (error.name === 'TypeError' && error.message.includes('Failed to fetch')) {
      throw new Error('Network error. Please check if backend server is running at http://localhost:5000');
    }
    
    throw error;
  }
};

/**
 * Get courses for upload dropdown
 */
export const getCoursesForUpload = async () => {
  try {
    console.log('📚 Fetching courses...');
    
    const response = await fetch(`${API_URL}/courses`);
    
    if (!response.ok) {
      console.warn('⚠️ Courses fetch failed:', response.status);
      // Return empty array instead of throwing
      return [];
    }
    
    const data = await response.json();
    console.log(`✅ Found ${data.courses?.length || 0} courses`);
    return data.courses || [];
    
  } catch (error) {
    console.error('❌ Error fetching courses:', error.message);
    // Return empty array to prevent UI crash
    return [];
  }
};

/**
 * Get pending notes (for admin)
 */
export const getPendingNotes = async () => {
  try {
    const token = localStorage.getItem('token');
    
    if (!token) {
      throw new Error('Authentication required');
    }
    
    const response = await fetch(`${API_URL}/admin/pending-notes`, {
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      }
    });
    
    if (!response.ok) {
      throw new Error(`Failed to fetch pending notes: ${response.status}`);
    }
    
    return await response.json();
    
  } catch (error) {
    console.error('Error fetching pending notes:', error);
    throw error;
  }
};

/**
 * Helper to check if user is authenticated
 */
export const isAuthenticated = () => {
  const token = localStorage.getItem('token');
  const user = localStorage.getItem('user');
  return !!(token && user);
};

/**
 * Helper to get current user
 */
export const getCurrentUser = () => {
  try {
    const userStr = localStorage.getItem('user');
    return userStr ? JSON.parse(userStr) : null;
  } catch (error) {
    console.error('Error parsing user:', error);
    return null;
  }
};

/**
 * Helper to logout user
 */
export const logoutUser = () => {
  localStorage.removeItem('token');
  localStorage.removeItem('user');
  console.log('👋 User logged out');
};

/**
 * Test backend connection
 */
export const testBackendConnection = async () => {
  try {
    const response = await fetch(`${API_URL}/health`);
    if (response.ok) {
      const data = await response.json();
      return {
        connected: true,
        data: data
      };
    }
    return {
      connected: false,
      error: `Status: ${response.status}`
    };
  } catch (error) {
    return {
      connected: false,
      error: error.message
    };
  }
};

/**
 * Upload with retry logic (optional)
 */
export const uploadFileWithRetry = async (formData, maxRetries = 2) => {
  let lastError;
  
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      console.log(`🔄 Upload attempt ${attempt}/${maxRetries}`);
      return await uploadFile(formData);
    } catch (error) {
      lastError = error;
      console.warn(`Attempt ${attempt} failed:`, error.message);
      
      // Don't retry on auth errors
      if (error.message.includes('login') || error.message.includes('Session')) {
        throw error;
      }
      
      // Wait before retry (exponential backoff)
      if (attempt < maxRetries) {
        const delay = Math.min(1000 * Math.pow(2, attempt), 10000);
        console.log(`⏳ Waiting ${delay}ms before retry...`);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }
  
  throw lastError;
};

export default {
  uploadFile,
  getCoursesForUpload,
  getPendingNotes,
  isAuthenticated,
  getCurrentUser,
  logoutUser,
  testBackendConnection,
  uploadFileWithRetry
};
